catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
   if (isLoading) {
      return;
   }

   if(newValue == '') {
	top.window.document.getElementById("poster_image").src = "";
   }

   top.window.document.getElementById("poster_image").src = g_form.getValue("poster_url");

}
